import { useState, useCallback } from 'react'
import { View, Text, Input, ScrollView } from '@tarojs/components'
import Taro, { useDidShow } from '@tarojs/taro'
import { isLoggedIn } from '../../utils/wx-login'
import { marketplaceApi, type MarketplaceTask, type CompanyGroup } from '../../api/marketplace'
import './index.scss'

const modeLabel: Record<string, string> = { task_package: '📦任务包', daily_rate: '📅人天' }

const formatBudget = (v: number) =>
  v >= 10000 ? `${(v / 10000).toFixed(1)}万` : `¥${v.toLocaleString()}`

const scoreColor = (s: number | null) =>
  s === null ? '#ccc' : s >= 70 ? '#52c41a' : s >= 50 ? '#faad14' : '#aaa'

const timeAgo = (d: string | null) => {
  if (!d) return ''
  const diff = Date.now() - new Date(d).getTime()
  const hours = Math.floor(diff / 3600000)
  if (hours < 24) return `${hours}小时前`
  return `${Math.floor(hours / 24)}天前`
}

const roles = ['全部', '摄影师', '平面设计师', '视频剪辑', '文案策划', '产品经理', '插画师', '模特', '化妆师', 'UI设计师']
const cities = ['全部', '北京', '上海', '广州', '深圳', '杭州', '成都', '远程']
const modes = ['全部', '任务包', '人天计费']
const sorts = [
  { label: '最新发布', value: 'latest' },
  { label: '匹配度', value: 'match' },
  { label: '预算高', value: 'budget' },
]

type ViewMode = 'flat' | 'list'

export default function MarketplacePage() {
  const [tasks, setTasks] = useState<MarketplaceTask[]>([])
  const [groups, setGroups] = useState<CompanyGroup[]>([])
  const [total, setTotal] = useState(0)
  const [companyCount, setCompanyCount] = useState(0)
  const [hint, setHint] = useState('')
  const [page, setPage] = useState(1)
  const [loading, setLoading] = useState(false)
  const [keyword, setKeyword] = useState('')
  const [filters, setFilters] = useState({ roleName: '', city: '', taskMode: '', sort: 'latest' })
  const [showFilter, setShowFilter] = useState('')
  const [viewMode, setViewMode] = useState<ViewMode>('flat')

  const loadTasks = useCallback(async (p = 1, append = false) => {
    if (loading || !isLoggedIn()) return
    setLoading(true)
    try {
      const params: any = { page: p, pageSize: 10, sort: filters.sort }
      if (filters.roleName && filters.roleName !== '全部') params.roleName = filters.roleName
      if (filters.city && filters.city !== '全部') params.city = filters.city
      if (filters.taskMode === '任务包') params.taskMode = 'task_package'
      else if (filters.taskMode === '人天计费') params.taskMode = 'daily_rate'
      if (keyword) params.keyword = keyword

      const res = await marketplaceApi.list(params)
      setTasks(prev => append ? [...prev, ...res.list] : res.list)
      setTotal(res.total)
      setCompanyCount(res.companyCount ?? 0)
      setHint(res.hint ?? '')
      setPage(p)
    } catch {}
    setLoading(false)
  }, [filters, keyword, loading])

  const loadGroups = useCallback(async () => {
    if (!isLoggedIn()) return
    try {
      const res = await marketplaceApi.listByCompany()
      setGroups(res.groups ?? [])
    } catch {}
  }, [])

  useDidShow(() => {
    loadTasks(1)
    loadGroups()
  })

  const onSearch = () => loadTasks(1)

  const selectFilter = (key: string, val: string) => {
    setFilters(prev => ({ ...prev, [key]: val }))
    setShowFilter('')
    setTimeout(() => loadTasks(1), 50)
  }

  const goDetail = (taskId: number) =>
    Taro.navigateTo({ url: `/subpackages/marketplace/pages/detail/index?id=${taskId}` })

  if (!isLoggedIn()) {
    return (
      <View className='mp-page'>
        <View className='login-hint'>
          <Text>请先登录后浏览服务广场</Text>
          <View className='login-btn' onClick={() => Taro.switchTab({ url: '/pages/index/index' })}>
            <Text className='login-btn-text'>去登录</Text>
          </View>
        </View>
      </View>
    )
  }

  // V3.4: 无零工库关系的空状态
  if (hint && tasks.length === 0 && !loading) {
    return (
      <View className='mp-page'>
        <View className='empty-pool'>
          <Text className='empty-pool-icon'>🏢</Text>
          <Text className='empty-pool-title'>暂无可浏览的任务</Text>
          <Text className='empty-pool-desc'>{hint}</Text>
          <View className='empty-pool-btn' onClick={() => Taro.switchTab({ url: '/pages/my/index' })}>
            <Text className='empty-pool-btn-text'>完善个人资料</Text>
          </View>
        </View>
      </View>
    )
  }

  return (
    <View className='mp-page'>
      {/* 搜索栏 */}
      <View className='search-bar'>
        <View className='search-input-wrap'>
          <Text className='search-icon'>🔍</Text>
          <Input
            className='search-input'
            placeholder='搜索任务/角色/技能...'
            value={keyword}
            onInput={e => setKeyword(e.detail.value)}
            onConfirm={onSearch}
          />
        </View>
      </View>

      {/* 筛选条 + 视图切换 */}
      <View className='filter-bar'>
        {[
          { key: 'roleName', label: filters.roleName || '角色', options: roles },
          { key: 'city', label: filters.city || '城市', options: cities },
          { key: 'taskMode', label: filters.taskMode || '模式', options: modes },
        ].map(f => (
          <View key={f.key} className={`filter-item ${showFilter === f.key ? 'active' : ''}`}
            onClick={() => setShowFilter(showFilter === f.key ? '' : f.key)}>
            <Text className='filter-text'>{f.label}</Text>
            <Text className='filter-arrow'>▼</Text>
            {showFilter === f.key && (
              <View className='filter-dropdown'>
                {f.options.map(opt => (
                  <View key={opt} className={`filter-option ${(filters as any)[f.key] === opt ? 'selected' : ''}`}
                    onClick={(e) => { e.stopPropagation(); selectFilter(f.key, opt) }}>
                    <Text>{opt}</Text>
                  </View>
                ))}
              </View>
            )}
          </View>
        ))}
        <View className='filter-item' onClick={() => {
          const idx = sorts.findIndex(s => s.value === filters.sort)
          const next = sorts[(idx + 1) % sorts.length]
          setFilters(prev => ({ ...prev, sort: next.value }))
          setTimeout(() => loadTasks(1), 50)
        }}>
          <Text className='filter-text'>{sorts.find(s => s.value === filters.sort)?.label}</Text>
          <Text className='filter-arrow'>↕</Text>
        </View>

        {/* V3.4: 视图切换 */}
        <View className='view-toggle'>
          <View className={`toggle-btn ${viewMode === 'flat' ? 'active' : ''}`}
            onClick={() => setViewMode('flat')}>
            <Text>▦</Text>
          </View>
          <View className={`toggle-btn ${viewMode === 'list' ? 'active' : ''}`}
            onClick={() => setViewMode('list')}>
            <Text>☰</Text>
          </View>
        </View>
      </View>

      <ScrollView className='content-scroll' scrollY
        onScrollToLower={() => { if (page * 10 < total) loadTasks(page + 1, true) }}>

        {/* V3.4: 信任提示条 */}
        {companyCount > 0 && (
          <View className='trust-banner'>
            <Text className='trust-text'>🏢 来自 {companyCount} 家合作企业的任务</Text>
          </View>
        )}

        {/* 扁平化视图 */}
        {viewMode === 'flat' && tasks.map(t => (
          <View key={t.taskId} className='task-card' onClick={() => goDetail(t.taskId)}>
            <View className='task-top'>
              <Text className='task-title'>{t.title}</Text>
              <Text className='task-budget'>{formatBudget(t.totalBudget)}</Text>
            </View>
            <View className='task-meta'>
              <Text className='meta-company'>🏢 {t.company.name}</Text>
              <Text className='meta-location'>📍{t.address || '远程'}</Text>
              <Text className='meta-mode'>{modeLabel[t.taskMode] || t.taskMode}</Text>
            </View>
            <View className='task-roles'>
              <Text className='roles-text'>需: {t.roles.map(r => `${r.roleName}×${r.headcount}`).join('  ')}</Text>
            </View>
            <View className='task-bottom'>
              <Text className='meta-time'>⏰ {timeAgo(t.publishedAt)}</Text>
              {t.matchScore !== null && (
                <View className='match-badge' style={{ backgroundColor: scoreColor(t.matchScore) }}>
                  <Text className='match-text'>匹配 {t.matchScore}</Text>
                </View>
              )}
            </View>
          </View>
        ))}

        {/* V3.4: 列表视图 */}
        {viewMode === 'list' && tasks.map(t => (
          <View key={t.taskId} className='task-list-row' onClick={() => goDetail(t.taskId)}>
            <View className='list-main'>
              <Text className='list-title'>{t.title}</Text>
              <Text className='list-company'>{t.company.name}</Text>
            </View>
            <View className='list-info'>
              <Text className='list-budget'>{formatBudget(t.totalBudget)}</Text>
              <Text className='list-roles'>{t.roles.length}个角色</Text>
            </View>
          </View>
        ))}

        {loading && <View className='loading-more'><Text>加载中...</Text></View>}
        {!loading && tasks.length === 0 && !hint && <View className='empty'><Text>暂无招募中的任务</Text></View>}

        {/* 下半区：按企业浏览 */}
        {groups.length > 0 && viewMode === 'flat' && (
          <>
            <View className='section-divider'>
              <View className='divider-line' />
              <Text className='divider-text'>按企业浏览</Text>
              <View className='divider-line' />
            </View>
            {groups.map((g, gi) => (
              <View key={gi} className='company-group'>
                <View className='company-header'>
                  <Text className='company-name'>🏢 {g.company.name}</Text>
                  <Text className='company-count'>{g.tasks.length}个任务 →</Text>
                </View>
                <ScrollView className='company-tasks' scrollX>
                  {g.tasks.map(t => (
                    <View key={t.taskId} className='mini-task-card' onClick={() => goDetail(t.taskId)}>
                      <Text className='mini-title'>{t.title}</Text>
                      <Text className='mini-budget'>{formatBudget(t.totalBudget)}</Text>
                    </View>
                  ))}
                </ScrollView>
              </View>
            ))}
          </>
        )}

        <View className='bottom-padding' />
      </ScrollView>
    </View>
  )
}

/**
 * V3.4 服务广场 + 个人统计 + 申请记录 API
 */
import { request } from './request'

// ══════════════════════════════════════════════════════
// 服务广场
// ══════════════════════════════════════════════════════

export interface MarketplaceTask {
  taskId: number
  title: string
  totalBudget: number
  taskMode: string
  address: string | null
  publishedAt: string | null
  company: { id: number; name: string; logoUrl: string | null }
  roles: { roleId: number; roleName: string; headcount: number; budget: number }[]
  matchScore: number | null
  dimensions: { skillMatch: number; cityMatch: number; budgetFit: number; freshness: number } | null
}

export interface CompanyGroup {
  company: { id: number; name: string; logoUrl: string | null }
  tasks: { taskId: number; title: string; totalBudget: number; taskMode: string; address: string | null; publishedAt: string | null }[]
}

export interface MarketplaceDetail {
  taskId: number
  title: string
  description: string | null
  totalBudget: number
  taskMode: string
  address: string | null
  startDate: string | null
  endDate: string | null
  publishedAt: string | null
  company: { id: number; name: string; logoUrl: string | null }
  roles: {
    roleId: number; roleName: string; headcount: number; budget: number
    skillTags: string | null; description: string | null; filledCount: number
    myApplicationStatus: string | null
  }[]
  matchScore: number | null
  dimensions: any
}

/** V3.4: 列表响应新增 companyCount + hint */
export interface MarketplaceListResponse {
  total: number
  page: number
  pageSize: number
  list: MarketplaceTask[]
  companyCount: number
  hint?: string
}

export interface CompanyGroupResponse {
  groups: CompanyGroup[]
  companyCount: number
  hint?: string
}

export const marketplaceApi = {
  /** 任务列表（V3.4: 仅零工库企业的任务） */
  list: (params: {
    roleName?: string; city?: string; taskMode?: string
    sort?: string; keyword?: string; page?: number; pageSize?: number
  }) =>
    request<MarketplaceListResponse>({
      url: '/marketplace/tasks', data: params,
    }),

  /** 按企业分组（V3.4: 仅零工库企业） */
  listByCompany: () =>
    request<CompanyGroupResponse>({
      url: '/marketplace/tasks', data: { groupBy: 'company' },
    }),

  /** 任务详情（V3.4: 校验零工库关系） */
  detail: (id: number) =>
    request<MarketplaceDetail>({ url: `/marketplace/tasks/${id}` }),

  /** 申请任务角色 */
  apply: (taskId: number, roleId: number, data: {
    intro: string; expectPay?: number; availableAt?: string
  }) =>
    request<{ message: string }>({
      url: `/marketplace/tasks/${taskId}/roles/${roleId}/apply`,
      method: 'POST', data,
    }),
}

// ══════════════════════════════════════════════════════
// 零工统计 + 信用分
// ══════════════════════════════════════════════════════

export interface WorkerStats {
  servedCompanies: number
  acceptedTasks: number
  inProgressTasks: number
  completedTasks: number
  creditScore: number
  creditLevel: { level: string; color: string }
  coverImage: string | null
  coverTemplate: string
}

export interface CreditDetail {
  total: number
  level: string
  color: string
  dimensions: {
    rating: { score: number; weight: string; raw: number }
    completion: { score: number; weight: string; raw: number }
    onTime: { score: number; weight: string; raw: number }
    noDispute: { score: number; weight: string; raw: number }
  }
}

export const workerStatsApi = {
  /** 个人统计 */
  getStats: () => request<WorkerStats>({ url: '/worker/stats' }),

  /** 信用分明细 */
  getCreditScore: () => request<CreditDetail>({ url: '/worker/credit-score' }),

  /** 更新封面 */
  updateCover: (data: { coverImage?: string; coverTemplate?: string }) =>
    request<{ message: string }>({ url: '/worker/cover-image', method: 'PUT', data }),
}

// ══════════════════════════════════════════════════════
// V3.4 NEW — 零工申请记录
// ══════════════════════════════════════════════════════

export interface WorkerApplication {
  applicationId: number
  status: 'pending' | 'approved' | 'rejected'
  intro: string
  expectPay: number | null
  rejectReason: string | null
  reviewedAt: string | null
  createdAt: string
  role: { roleId: number; roleName: string; budget: number }
  task: {
    taskId: number; title: string; status: string; taskMode: string
    company: { id: number; name: string; logoUrl: string | null }
  }
}

export const workerApplicationApi = {
  /** 我的申请列表 */
  list: (status?: string) =>
    request<{ total: number; list: WorkerApplication[] }>({
      url: '/worker/applications', data: status ? { status } : undefined,
    }),
}

/**
 * V3.4 服务广场 — 零工库权限模型 + 申请审核
 *
 * 零工端：
 *   GET  /marketplace/tasks              任务列表（仅零工库关联企业的任务）
 *   GET  /marketplace/tasks/:id          任务详情（校验零工库关系）
 *   POST /marketplace/tasks/:taskId/roles/:roleId/apply  提交申请
 *
 * 企业端：
 *   GET  /tasks/:id/applications         查看某任务的申请列表
 *   POST /tasks/:id/applications/:appId/review  审核申请（确认/婉拒）
 *
 * 零工端（个人）：
 *   GET  /worker/applications            我的申请列表
 */
import {
  Controller, Get, Post, Param, Query, Body,
  UseGuards, ParseIntPipe, BadRequestException, ForbiddenException,
  ConflictException, NotFoundException, Logger,
} from '@nestjs/common';
import { ApiTags, ApiOperation, ApiBearerAuth, ApiQuery } from '@nestjs/swagger';
import { IsString, IsOptional, IsNumber, IsIn, MinLength, MaxLength, Min } from 'class-validator';
import { Type } from 'class-transformer';
import { PrismaService } from '../../prisma';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { CurrentUser } from '../auth/decorators/current-user.decorator';
import type { CurrentUserPayload } from '../auth/decorators/current-user.decorator';
import { RecommendationService } from './recommendation.service';

// ── DTOs ──────────────────────────────────────────────

class ApplyDto {
  @IsString()
  @MinLength(20, { message: '自我介绍至少20字' })
  @MaxLength(200, { message: '自我介绍最多200字' })
  intro: string;

  @IsOptional()
  @IsNumber()
  @Min(0)
  @Type(() => Number)
  expectPay?: number;

  @IsOptional()
  @IsString()
  availableAt?: string;
}

class ReviewDto {
  @IsIn(['approved', 'rejected'], { message: 'action 必须是 approved 或 rejected' })
  action: 'approved' | 'rejected';

  @IsOptional()
  @IsString()
  @MaxLength(200)
  rejectReason?: string;
}

// ── 零工端：服务广场 ─────────────────────────────────

@ApiTags('marketplace')
@Controller('marketplace')
@UseGuards(JwtAuthGuard)
@ApiBearerAuth('access-token')
export class MarketplaceController {
  private readonly logger = new Logger(MarketplaceController.name);

  constructor(
    private readonly prisma: PrismaService,
    private readonly recommendSvc: RecommendationService,
  ) {}

  /**
   * V3.4 核心：获取当前零工所在零工库的企业 ID 列表
   */
  private async getPoolCompanyIds(workerId: bigint): Promise<bigint[]> {
    const pools = await this.prisma.companyWorkerPool.findMany({
      where: {
        workerId,
        inviteStatus: { in: ['registered', 'verified'] },
      },
      select: { companyId: true },
    });
    return pools.map(p => p.companyId);
  }

  // ================================================================
  // GET /marketplace/tasks — 服务广场任务列表（V3.4: 仅零工库企业）
  // ================================================================
  @Get('tasks')
  @ApiOperation({ summary: '服务广场任务列表（仅零工库关联企业）' })
  @ApiQuery({ name: 'roleName', required: false })
  @ApiQuery({ name: 'city', required: false })
  @ApiQuery({ name: 'taskMode', required: false })
  @ApiQuery({ name: 'sort', required: false, description: 'latest | match | budget' })
  @ApiQuery({ name: 'keyword', required: false })
  @ApiQuery({ name: 'groupBy', required: false, description: 'company' })
  @ApiQuery({ name: 'page', required: false })
  @ApiQuery({ name: 'pageSize', required: false })
  async listTasks(
    @CurrentUser() user: CurrentUserPayload,
    @Query('roleName') roleName?: string,
    @Query('city') city?: string,
    @Query('taskMode') taskMode?: string,
    @Query('sort') sort?: string,
    @Query('keyword') keyword?: string,
    @Query('groupBy') groupBy?: string,
    @Query('page') page = 1,
    @Query('pageSize') pageSize = 10,
  ) {
    const p = Number(page);
    const ps = Number(pageSize);

    // V3.4: 获取零工库关联的企业 IDs
    const companyIds = await this.getPoolCompanyIds(BigInt(user.userId));

    // 如果零工不在任何企业的零工库中，返回空 + 提示
    if (companyIds.length === 0) {
      return groupBy === 'company'
        ? { groups: [], companyCount: 0, hint: '您尚未被企业纳入零工库，完善个人资料等待企业邀请' }
        : { total: 0, page: p, pageSize: ps, list: [], companyCount: 0, hint: '您尚未被企业纳入零工库，完善个人资料等待企业邀请' };
    }

    // V3.4: 基础 where — 只查零工库内企业的 published 任务
    const where: any = {
      status: 'published',
      companyId: { in: companyIds },
    };
    if (city) where.address = { contains: city };
    if (taskMode) where.taskMode = taskMode;
    if (keyword) where.title = { contains: keyword };
    if (roleName) where.taskRoles = { some: { roleName: { contains: roleName } } };

    // 按企业分组模式
    if (groupBy === 'company') {
      const tasks = await this.prisma.task.findMany({
        where,
        include: {
          company: { select: { id: true, name: true, logoUrl: true } },
          taskRoles: { select: { id: true, roleName: true, headcount: true, budget: true } },
        },
        orderBy: { publishedAt: 'desc' },
        take: 100,
      });

      const groupMap = new Map<string, any>();
      for (const t of tasks) {
        const cid = String(t.companyId);
        if (!groupMap.has(cid)) {
          groupMap.set(cid, { company: { id: Number(t.company.id), name: t.company.name, logoUrl: t.company.logoUrl }, tasks: [] });
        }
        groupMap.get(cid).tasks.push({
          taskId: Number(t.id),
          title: t.title,
          totalBudget: Number(t.totalBudget),
          taskMode: t.taskMode,
          address: t.address,
          publishedAt: t.publishedAt,
          roles: t.taskRoles.map(r => ({ roleName: r.roleName, headcount: r.headcount, budget: Number(r.budget) })),
        });
      }

      return {
        groups: [...groupMap.values()].sort((a, b) => b.tasks.length - a.tasks.length),
        companyCount: companyIds.length,
      };
    }

    // 标准分页模式
    const orderBy: any = sort === 'budget'
      ? { totalBudget: 'desc' }
      : { publishedAt: 'desc' };

    const [list, total] = await Promise.all([
      this.prisma.task.findMany({
        where,
        include: {
          company: { select: { id: true, name: true, logoUrl: true } },
          taskRoles: { select: { id: true, roleName: true, headcount: true, budget: true, skillTags: true } },
        },
        orderBy,
        skip: (p - 1) * ps,
        take: ps,
      }),
      this.prisma.task.count({ where }),
    ]);

    // match score
    let scoreMap: Map<number, any> = new Map();
    if (sort === 'match') {
      const rec = await this.recommendSvc.recommendTasksForWorker(user.userId, 200, 1);
      for (const r of rec.list) scoreMap.set(r.taskId, { score: r.score, dimensions: r.dimensions });
    }

    const items = list.map(t => {
      const tid = Number(t.id);
      const recData = scoreMap.get(tid);
      return {
        taskId: tid,
        title: t.title,
        totalBudget: Number(t.totalBudget),
        taskMode: t.taskMode,
        address: t.address,
        publishedAt: t.publishedAt,
        company: { id: Number(t.company.id), name: t.company.name, logoUrl: t.company.logoUrl },
        roles: t.taskRoles.map(r => ({
          roleId: Number(r.id),
          roleName: r.roleName,
          headcount: r.headcount,
          budget: Number(r.budget),
        })),
        matchScore: recData?.score ?? null,
        dimensions: recData?.dimensions ?? null,
      };
    });

    if (sort === 'match') {
      items.sort((a, b) => (b.matchScore ?? 0) - (a.matchScore ?? 0));
    }

    return { total, page: p, pageSize: ps, list: items, companyCount: companyIds.length };
  }

  // ================================================================
  // GET /marketplace/tasks/:id — 任务详情（V3.4: 校验零工库关系）
  // ================================================================
  @Get('tasks/:id')
  @ApiOperation({ summary: '服务广场任务详情（校验零工库关系）' })
  async taskDetail(
    @Param('id', ParseIntPipe) id: number,
    @CurrentUser() user: CurrentUserPayload,
  ) {
    const task = await this.prisma.task.findFirst({
      where: { id: BigInt(id), status: 'published' },
      include: {
        company: { select: { id: true, name: true, logoUrl: true } },
        taskRoles: {
          select: {
            id: true, roleName: true, headcount: true, budget: true,
            skillTags: true, description: true,
            assignments: { select: { id: true }, where: { status: { in: ['invited', 'accepted'] } } },
          },
        },
      },
    });

    if (!task) throw new BadRequestException('任务不存在或未发布');

    // V3.4: 校验零工库关系
    const companyIds = await this.getPoolCompanyIds(BigInt(user.userId));
    if (!companyIds.some(cid => cid === task.companyId)) {
      throw new ForbiddenException('您不在该企业的零工库中，无法查看此任务');
    }

    // 检查当前零工是否已申请过
    const myApplications = await this.prisma.taskApplication.findMany({
      where: { workerId: BigInt(user.userId), taskRole: { taskId: BigInt(id) } },
      select: { id: true, taskRoleId: true, status: true },
    });
    const appliedMap = new Map(myApplications.map(a => [String(a.taskRoleId), a.status]));

    // 获取匹配度
    const rec = await this.recommendSvc.recommendTasksForWorker(user.userId, 200, 1);
    const matchData = rec.list.find(r => r.taskId === id);

    return {
      taskId: Number(task.id),
      title: task.title,
      description: task.description,
      totalBudget: Number(task.totalBudget),
      taskMode: task.taskMode,
      address: task.address,
      startDate: task.startDate,
      endDate: task.endDate,
      publishedAt: task.publishedAt,
      company: { id: Number(task.company.id), name: task.company.name, logoUrl: task.company.logoUrl },
      roles: task.taskRoles.map(r => ({
        roleId: Number(r.id),
        roleName: r.roleName,
        headcount: r.headcount,
        budget: Number(r.budget),
        skillTags: r.skillTags,
        description: r.description,
        filledCount: r.assignments.length,
        myApplicationStatus: appliedMap.get(String(r.id)) ?? null,
      })),
      matchScore: matchData?.score ?? null,
      dimensions: matchData?.dimensions ?? null,
    };
  }

  // ================================================================
  // POST /marketplace/tasks/:taskId/roles/:roleId/apply — 提交申请
  // ================================================================
  @Post('tasks/:taskId/roles/:roleId/apply')
  @ApiOperation({ summary: '零工申请任务角色' })
  async apply(
    @Param('taskId', ParseIntPipe) taskId: number,
    @Param('roleId', ParseIntPipe) roleId: number,
    @CurrentUser() user: CurrentUserPayload,
    @Body() dto: ApplyDto,
  ) {
    if (user.userType !== 'worker') {
      throw new ForbiddenException('仅零工账号可申请');
    }

    const worker = await this.prisma.worker.findUnique({ where: { id: BigInt(user.userId) } });
    if (!worker?.isVerified) {
      throw new BadRequestException('请先完成实名认证');
    }

    const role = await this.prisma.taskRole.findUnique({
      where: { id: BigInt(roleId) },
      include: { task: true },
    });
    if (!role || Number(role.taskId) !== taskId) {
      throw new BadRequestException('角色不存在');
    }
    if (role.task.status !== 'published') {
      throw new BadRequestException('任务未在招募中');
    }

    // V3.4: 校验零工库关系
    const companyIds = await this.getPoolCompanyIds(BigInt(user.userId));
    if (!companyIds.some(cid => cid === role.task.companyId)) {
      throw new ForbiddenException('您不在该企业的零工库中，无法申请');
    }

    // 检查重复
    const existing = await this.prisma.taskApplication.findUnique({
      where: { taskRoleId_workerId: { taskRoleId: BigInt(roleId), workerId: BigInt(user.userId) } },
    });
    if (existing) {
      if (existing.status === 'pending') throw new ConflictException('您已申请该角色，请等待审核');
      if (existing.status === 'approved') throw new ConflictException('您的申请已通过');
      // rejected → 允许重新申请
      await this.prisma.taskApplication.update({
        where: { id: existing.id },
        data: {
          intro: dto.intro,
          expectPay: dto.expectPay,
          availableAt: dto.availableAt ? new Date(dto.availableAt) : null,
          status: 'pending',
          rejectReason: null,
          reviewedAt: null,
          reviewedBy: null,
        },
      });
      return { message: '重新申请成功，请等待企业审核' };
    }

    await this.prisma.taskApplication.create({
      data: {
        taskRoleId: BigInt(roleId),
        workerId: BigInt(user.userId),
        intro: dto.intro,
        expectPay: dto.expectPay,
        availableAt: dto.availableAt ? new Date(dto.availableAt) : null,
      },
    });

    return { message: '申请成功，请等待企业审核' };
  }
}

