    });

    // 6b. 确保零工在企业零工库中
    const existingPool = await tx.companyWorkerPool.findFirst({
      where: { companyId: BigInt(companyId), workerId: BigInt(workerId) },
      select: { id: true, inviteStatus: true },
    });

