import {
  Controller,
  Get,
  Param,
  Query,
  ParseIntPipe,
  UseGuards,
  DefaultValuePipe,
} from '@nestjs/common';
import {
  ApiTags,
  ApiBearerAuth,
  ApiOperation,
  ApiQuery,
} from '@nestjs/swagger';
import { MessageService } from './message.service';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { CurrentUser } from '../auth/decorators/current-user.decorator';

interface JwtPayload {
  userId: number;
  companyId?: number;
  userType: 'company' | 'worker';
}

@ApiTags('message')
@ApiBearerAuth('access-token')
@UseGuards(JwtAuthGuard)
@Controller('conversations')
export class MessageController {
  constructor(private readonly messageService: MessageService) {}

  /**
   * GET /api/v1/conversations
   * 会话列表（含最后一条消息 + 未读数）
   */
  @Get()
  @ApiOperation({ summary: '会话列表' })
  @ApiQuery({ name: 'page',     required: false, type: Number })
  @ApiQuery({ name: 'pageSize', required: false, type: Number })
  async listConversations(
    @CurrentUser() user: JwtPayload,
    @Query('page',     new DefaultValuePipe(1),  ParseIntPipe) page: number,
    @Query('pageSize', new DefaultValuePipe(20), ParseIntPipe) pageSize: number,
  ) {
    return this.messageService.listConversations(user.userId, user.userType, page, pageSize);
  }

  /**
   * GET /api/v1/conversations/:id/messages
   * 历史消息（分页，加载时自动标记已读）
   */
  @Get(':id/messages')
  @ApiOperation({ summary: '历史消息（分页）' })
  @ApiQuery({ name: 'page',     required: false, type: Number })
  @ApiQuery({ name: 'pageSize', required: false, type: Number })
  async listMessages(
    @CurrentUser() user: JwtPayload,
    @Param('id', ParseIntPipe) conversationId: number,
    @Query('page',     new DefaultValuePipe(1),  ParseIntPipe) page: number,
    @Query('pageSize', new DefaultValuePipe(30), ParseIntPipe) pageSize: number,
  ) {
    return this.messageService.listMessages(conversationId, user.userId, user.userType, page, pageSize);
  }
}

import {
  WebSocketGateway,
  WebSocketServer,
  SubscribeMessage,
  OnGatewayConnection,
  OnGatewayDisconnect,
  MessageBody,
  ConnectedSocket,
  WsException,
} from '@nestjs/websockets';
import { Server, Socket } from 'socket.io';
import { Logger, UseGuards } from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { InjectRedis } from '@nestjs-modules/ioredis';
import Redis from 'ioredis';
import { MessageService } from './message.service';

interface AuthSocket extends Socket {
  userId: number;
  userType: 'company' | 'worker';
}

// ──────────────────────────────────────────────
// WebSocket 事件常量
// ──────────────────────────────────────────────
export const WS_EVENTS = {
  SEND_MESSAGE:    'send_message',
  NEW_MESSAGE:     'new_message',
  MESSAGE_READ:    'message_read',
  READ_RECEIPT:    'read_receipt',
  ERROR:           'ws_error',
  ONLINE_USERS:    'online_users',
} as const;

// Redis 频道
const REDIS_CHANNEL = 'wc:chat:broadcast';

@WebSocketGateway({
  cors: { origin: '*', credentials: true },
  namespace: '/chat',
  transports: ['websocket', 'polling'],
})
export class MessageGateway implements OnGatewayConnection, OnGatewayDisconnect {
  @WebSocketServer() server: Server;

  private readonly logger = new Logger(MessageGateway.name);

  // socketId → { userId, userType }
  private readonly onlineMap = new Map<string, { userId: number; userType: string }>();

  // userId → Set<socketId>（一人多端）
  private readonly userSocketMap = new Map<number, Set<string>>();

  // Redis subscriber 专用客户端
  private redisSub: Redis;

  constructor(
    private readonly jwtService: JwtService,
    @InjectRedis() private readonly redis: Redis,
    private readonly messageService: MessageService,
  ) {
    // 创建独立订阅客户端（subscriber 不能执行普通命令）
    this.redisSub = redis.duplicate();
    this.redisSub.subscribe(REDIS_CHANNEL);
    this.redisSub.on('message', (_channel, payload) => {
      this.handleRedisMessage(payload);
    });
  }

  // ── 连接：验证 JWT ────────────────────────────────────────
  async handleConnection(client: AuthSocket) {
    try {
      const token =
        client.handshake.auth?.token ||
        client.handshake.headers?.authorization?.replace('Bearer ', '');

      if (!token) throw new WsException('Missing token');

      const payload = this.jwtService.verify(token);
      client.userId   = payload.sub;
      client.userType = payload.type;   // 'company' | 'worker'

      // 加入个人房间（用于私信推送）
      const userRoom = `user:${client.userId}`;
      client.join(userRoom);

      // 记录在线状态
      this.onlineMap.set(client.id, { userId: client.userId, userType: client.userType });
      if (!this.userSocketMap.has(client.userId)) {
        this.userSocketMap.set(client.userId, new Set());
      }
      this.userSocketMap.get(client.userId)!.add(client.id);

      this.logger.log(`✅ Connected: user=${client.userId}(${client.userType}) socket=${client.id}`);
    } catch (err) {
      this.logger.warn(`❌ Auth failed for socket ${client.id}: ${err.message}`);
      client.emit(WS_EVENTS.ERROR, { code: 401, message: 'Unauthorized' });
      client.disconnect();
    }
  }

  // ── 断开：清理状态 ────────────────────────────────────────
  handleDisconnect(client: AuthSocket) {
    const info = this.onlineMap.get(client.id);
    if (info) {
      this.onlineMap.delete(client.id);
      const sockets = this.userSocketMap.get(info.userId);
      if (sockets) {
        sockets.delete(client.id);
        if (sockets.size === 0) this.userSocketMap.delete(info.userId);
      }
    }
    this.logger.log(`🔌 Disconnected: socket=${client.id}`);
  }

  // ── 发送消息 ─────────────────────────────────────────────
  @SubscribeMessage(WS_EVENTS.SEND_MESSAGE)
  async handleSendMessage(
    @ConnectedSocket() client: AuthSocket,
    @MessageBody() dto: {
      conversationId: number;
      type?: 'text' | 'image' | 'file';
      content: string;
      fileName?: string;
      fileSize?: number;
    },
  ) {
    if (!client.userId) throw new WsException('Unauthorized');

    const { conversationId, type = 'text', content, fileName, fileSize } = dto;

    // 1. 鉴权：确认用户属于该会话
    const conversation = await this.messageService.getConversationById(conversationId);
    if (!conversation) throw new WsException('Conversation not found');

    const allowed =
      (client.userType === 'company' && Number(conversation.companyUserId) === client.userId) ||
      (client.userType === 'worker'  && Number(conversation.workerId)       === client.userId);
    if (!allowed) throw new WsException('Forbidden');

    // 2. 持久化到 MongoDB
    const saved = await this.messageService.saveMessage({
      conversationId,
      senderId: client.userId,
      senderType: client.userType,
      type,
      content,
      fileName: fileName ?? null,
      fileSize: fileSize ?? null,
    });

    // 3. 更新会话最后消息时间
    await this.messageService.updateLastMsgAt(conversationId);

    // 4. 通过 Redis Pub/Sub 广播（支持多实例）
    const payload = JSON.stringify({
      event:          WS_EVENTS.NEW_MESSAGE,
      conversationId,
      message: {
        id:           saved._id,
        conversationId,
        senderId:     client.userId,
        senderType:   client.userType,
        type,
        content,
        fileName:     fileName ?? null,
        fileSize:     fileSize ?? null,
        createdAt:    saved.createdAt,
      },
      targetUserIds: [
        Number(conversation.companyUserId),
        Number(conversation.workerId),
      ],
    });
    await this.redis.publish(REDIS_CHANNEL, payload);

    return { success: true, messageId: String(saved._id) };
  }

  // ── 已读回执 ─────────────────────────────────────────────
  @SubscribeMessage(WS_EVENTS.MESSAGE_READ)
  async handleMessageRead(
    @ConnectedSocket() client: AuthSocket,
    @MessageBody() dto: { conversationId: number; messageIds: string[] },
  ) {
    if (!client.userId) throw new WsException('Unauthorized');

    const { conversationId, messageIds } = dto;
    await this.messageService.markAsRead(messageIds, client.userId);

    // 通知对方已读
    const conversation = await this.messageService.getConversationById(conversationId);
    if (conversation) {
      const otherId =
        client.userType === 'company'
          ? Number(conversation.workerId)
          : Number(conversation.companyUserId);

      this.sendToUser(otherId, WS_EVENTS.READ_RECEIPT, { conversationId, messageIds, readBy: client.userId });
    }

    return { success: true };
  }

  // ── Redis Pub/Sub 消费 ────────────────────────────────────
  private handleRedisMessage(payload: string) {
    try {
      const data = JSON.parse(payload);
      const { event, message, targetUserIds } = data;

      // 推送给所有目标用户（含多端）
      (targetUserIds as number[]).forEach((uid) => {
        this.sendToUser(uid, event, message);
      });
    } catch (e) {
      this.logger.error('Redis message parse error', e);
    }
  }

  // ── 工具：向指定用户所有 socket 推送 ────────────────────
  sendToUser(userId: number, event: string, data: unknown) {
    this.server.to(`user:${userId}`).emit(event, data);
  }

  // ── 工具：向 Room 广播（供外部 Service 调用） ────────────
  broadcastToRoom(room: string, event: string, data: unknown) {
    this.server.to(room).emit(event, data);
  }

  // ── 在线用户数（运维/调试用） ────────────────────────────
  getOnlineCount(): number {
    return this.userSocketMap.size;
  }
}

import {
  Injectable,
  NotFoundException,
  ForbiddenException,
} from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { Model } from 'mongoose';
import { PrismaService } from '../../prisma';
import { Message, MessageDocument } from './schemas/message.schema';

// ─────────────────────────────────────────────
// DTOs（内部使用）
// ─────────────────────────────────────────────
export interface SaveMessageDto {
  conversationId: number;
  senderId: number;
  senderType: 'company' | 'worker';
  type: 'text' | 'image' | 'file';
  content: string;
  fileName: string | null;
  fileSize: number | null;
}

@Injectable()
export class MessageService {
  constructor(
    private readonly prisma: PrismaService,
    @InjectModel(Message.name) private readonly messageModel: Model<MessageDocument>,
  ) {}

  // ──────────────────────────────────────────
  // 会话管理
  // ──────────────────────────────────────────

  /**
   * 获取或创建会话（taskId + companyUserId + workerId 唯一）
   */
  async getOrCreateConversation(taskId: bigint, companyUserId: bigint, workerId: bigint) {
    return this.prisma.conversation.upsert({
      where: {
        taskId_companyUserId_workerId: { taskId, companyUserId, workerId },
      },
      create: { taskId, companyUserId, workerId },
      update: {},
    });
  }

  /** 按 ID 查询会话 */
  async getConversationById(id: number) {
    return this.prisma.conversation.findUnique({
      where: { id: BigInt(id) },
    });
  }

  /**
   * 用户会话列表（含最后一条消息 + 未读数）
   * GET /conversations
   */
  async listConversations(
    userId: number,
    userType: 'company' | 'worker',
    page = 1,
    pageSize = 20,
  ) {
    const skip = (page - 1) * pageSize;

    // 查询与用户相关的所有会话
    const where =
      userType === 'company'
        ? { companyUserId: BigInt(userId) }
        : { workerId: BigInt(userId) };

    const [total, conversations] = await Promise.all([
      this.prisma.conversation.count({ where }),
      this.prisma.conversation.findMany({
        where,
        orderBy: { lastMsgAt: 'desc' },
        skip,
        take: pageSize,
      }),
    ]);

    // 批量从 MongoDB 拉取每个会话的最后一条消息 + 未读数
    const convIds = conversations.map((c) => Number(c.id));
    const [lastMsgs, unreadCounts] = await Promise.all([
      this.getLastMessages(convIds),
      this.getUnreadCounts(convIds, userId),
    ]);

    const list = conversations.map((conv) => ({
      id:             Number(conv.id),
      taskId:         Number(conv.taskId),
      companyUserId:  Number(conv.companyUserId),
      workerId:       Number(conv.workerId),
      lastMsgAt:      conv.lastMsgAt,
      lastMessage:    lastMsgs.get(Number(conv.id)) ?? null,
      unreadCount:    unreadCounts.get(Number(conv.id)) ?? 0,
    }));

    return { list, total, page, pageSize };
  }

  /**
   * 历史消息（分页，倒序）
   * GET /conversations/:id/messages
   */
  async listMessages(
    conversationId: number,
    userId: number,
    userType: 'company' | 'worker',
    page = 1,
    pageSize = 30,
  ) {
    // 验证权限
    const conv = await this.getConversationById(conversationId);
    if (!conv) throw new NotFoundException('Conversation not found');

    const allowed =
      (userType === 'company' && Number(conv.companyUserId) === userId) ||
      (userType === 'worker'  && Number(conv.workerId)       === userId);
    if (!allowed) throw new ForbiddenException();

    const skip = (page - 1) * pageSize;
    const [total, messages] = await Promise.all([
      this.messageModel.countDocuments({ conversationId }),
      this.messageModel
        .find({ conversationId })
        .sort({ createdAt: -1 })
        .skip(skip)
        .limit(pageSize)
        .lean(),
    ]);

    // 自动标记为已读
    const unreadIds = messages
      .filter((m) => !m.readBy.includes(userId))
      .map((m) => String(m._id));
    if (unreadIds.length) {
      await this.markAsRead(unreadIds, userId);
    }

    return {
      list: messages.map(this.formatMessage),
      total,
      page,
      pageSize,
    };
  }

  // ──────────────────────────────────────────
  // 消息存储
  // ──────────────────────────────────────────

  async saveMessage(dto: SaveMessageDto): Promise<MessageDocument> {
    const msg = new this.messageModel({
      ...dto,
      readBy: [dto.senderId],
      createdAt: new Date(),
    });
    return msg.save();
  }

  async updateLastMsgAt(conversationId: number) {
    await this.prisma.conversation.update({
      where: { id: BigInt(conversationId) },
      data:  { lastMsgAt: new Date() },
    });
  }

  async markAsRead(messageIds: string[], userId: number) {
    await this.messageModel.updateMany(
      { _id: { $in: messageIds } },
      { $addToSet: { readBy: userId } },
    );
  }

  // ──────────────────────────────────────────
  // 辅助方法
  // ──────────────────────────────────────────

  private async getLastMessages(convIds: number[]): Promise<Map<number, unknown>> {
    // 每个会话取最后一条
    const docs = await this.messageModel
      .aggregate([
        { $match: { conversationId: { $in: convIds } } },
        { $sort:  { conversationId: 1, createdAt: -1 } },
        { $group: { _id: '$conversationId', doc: { $first: '$$ROOT' } } },
      ])
      .exec();

    return new Map(docs.map((d) => [d._id as number, this.formatMessage(d.doc)]));
  }

  private async getUnreadCounts(convIds: number[], userId: number): Promise<Map<number, number>> {
    const docs = await this.messageModel
      .aggregate([
        {
          $match: {
            conversationId: { $in: convIds },
            readBy: { $not: { $elemMatch: { $eq: userId } } },
          },
        },
        { $group: { _id: '$conversationId', count: { $sum: 1 } } },
      ])
      .exec();

    return new Map(docs.map((d) => [d._id as number, d.count as number]));
  }

  private formatMessage(m: any) {
    return {
      id:             String(m._id),
      conversationId: m.conversationId,
      senderId:       m.senderId,
      senderType:     m.senderType,
      type:           m.type,
      content:        m.content,
      fileName:       m.fileName,
      fileSize:       m.fileSize,
      readBy:         m.readBy,
      createdAt:      m.createdAt,
    };
  }
}

import { useState, useEffect, useCallback, useRef } from 'react'
import { View, Text, Input, ScrollView } from '@tarojs/components'
import Taro from '@tarojs/taro'
import { request } from '../../api/request'
import { useUserStore } from '../../stores/user'
import './index.scss'

function formatTime(ts: string) {
  const d = new Date(ts)
  const now = new Date()
  if (d.toDateString() === now.toDateString()) {
    return `${String(d.getHours()).padStart(2, '0')}:${String(d.getMinutes()).padStart(2, '0')}`
  }
  return `${d.getMonth() + 1}/${d.getDate()}`
}

export default function MessagePage() {
  const userStore = useUserStore()
  const [conversations, setConversations] = useState<any[]>([])
  const [activeConv, setActiveConv] = useState<any>(null)
  const [messages, setMessages] = useState<any[]>([])
  const [inputText, setInputText] = useState('')
  const wsRef = useRef<any>(null)
  const msgScrollId = useRef(`scroll-${Date.now()}`)

  // 加载会话列表
  const loadConversations = useCallback(async () => {
    try {
      const res: any = await request({ url: '/conversations', method: 'GET' })
      setConversations(res.data ?? res)
    } catch {}
  }, [])

  // 加载聊天记录
  const loadHistory = useCallback(async (convId: number) => {
    try {
      const res: any = await request({ url: `/conversations/${convId}/messages`, method: 'GET' })
      setMessages(res.data ?? res)
    } catch {}
  }, [])

  // WebSocket 连接
  const connectWs = useCallback(() => {
    const token = Taro.getStorageSync('wc_token')
    if (!token) return
    const apiBase = (process.env.TARO_APP_API_BASE as string || 'http://localhost:3000/api/v1')
    const wsBase = apiBase.replace('/api/v1', '').replace('http', 'ws')
    const wsTask = Taro.connectSocket({
      url: `${wsBase}/chat?token=${token}`,
      protocols: [],
    })
    wsRef.current = wsTask
    ;(wsTask as any).onMessage?.((msgEvent: any) => {
      try {
        const data = JSON.parse(msgEvent.data as string)
        if (data.event === 'new_message') {
          const msg = data.data
          setMessages(prev => [...prev, msg])
          // 更新会话列表最后消息
          setConversations(prev => prev.map(c =>
            c.id === msg.conversationId ? { ...c, lastMsgAt: msg.createdAt } : c
          ))
        }
      } catch {}
    })
  }, [])

  useEffect(() => {
    loadConversations()
    connectWs()
    return () => wsRef.current?.close?.()
  }, [])

  const openConversation = useCallback(async (conv: any) => {
    setActiveConv(conv)
    setMessages([])
    await loadHistory(conv.id)
  }, [loadHistory])

  const sendMessage = useCallback(() => {
    if (!inputText.trim() || !wsRef.current || !activeConv) return
    const payload = {
      event: 'send_message',
      data: {
        conversationId: activeConv.id,
        receiverId: activeConv.companyUserId,
        content: inputText.trim(),
        taskId: activeConv.taskId,
      },
    }
    wsRef.current.send({ data: JSON.stringify(payload) })
    // 乐观更新
    setMessages(prev => [...prev, {
      tempId: `t${Date.now()}`,
      senderId: userStore.userId,
      senderType: 'worker',
      content: inputText.trim(),
      createdAt: new Date().toISOString(),
    }])
    setInputText('')
  }, [inputText, activeConv, userStore.userId])

  // 会话列表视图
  if (!activeConv) {
    return (
      <View className='page'>
        <View className='top-bar'>
          <Text className='page-title'>消息</Text>
        </View>
        {conversations.length === 0 && (
          <View className='empty'>
            <Text className='empty-text'>暂无会话</Text>
          </View>
        )}
        {conversations.map(conv => (
          <View key={conv.id} className='conv-item' onClick={() => openConversation(conv)}>
            <View className='conv-avatar'>
              <Text className='avatar-text'>企</Text>
            </View>
            <View className='conv-info'>
              <Text className='conv-title'>任务#{conv.taskId}</Text>
              <Text className='conv-last-msg'>{conv.lastMsg || '暂无消息'}</Text>
            </View>
            <Text className='conv-time'>{conv.lastMsgAt ? formatTime(conv.lastMsgAt) : ''}</Text>
          </View>
        ))}
      </View>
    )
  }

  // 聊天视图
  const myId = userStore.userId
  return (
    <View className='page chat-page'>
      <View className='chat-header'>
        <Text className='back-btn' onClick={() => setActiveConv(null)}>‹ 返回</Text>
        <Text className='chat-title'>任务#{activeConv.taskId}</Text>
      </View>
      <ScrollView
        className='msg-scroll'
        scrollY
        scrollIntoView={msgScrollId.current}
        scrollWithAnimation
      >
        {messages.map((msg, i) => {
          const isSelf = msg.senderId === myId && msg.senderType === 'worker'
          return (
            <View key={msg._id || msg.tempId || i} className={`msg-row ${isSelf ? 'self' : 'other'}`}>
              <View className={`bubble ${isSelf ? 'bubble-self' : 'bubble-other'}`}>
                <Text className='bubble-text'>{msg.content}</Text>
              </View>
              <Text className='msg-time'>{formatTime(msg.createdAt)}</Text>
            </View>
          )
        })}
        <View id={msgScrollId.current} />
      </ScrollView>
      <View className='input-bar'>
        <Input
          className='msg-input'
          value={inputText}
          placeholder='说点什么...'
          onInput={(e: any) => setInputText(e.detail.value)}
          onConfirm={sendMessage}
          confirmType='send'
        />
        <View className='send-btn' onClick={sendMessage}>
          <Text className='send-text'>发送</Text>
        </View>
      </View>
    </View>
  )
}

/**
 * TaskNoGeneratorService — V3.7 任务/项目编号生成器
 *
 * 格式:
 *   任务编号:  TSK-YYYYMMDD-NNN
 *   项目编号:  PRJ-YYYYMMDD-NNN
 *
 * 实现: Redis INCR 保证原子性 + 并发安全
 * Key TTL: 48h（防止跨日残留影响下一天的序号）
 */
import { Injectable, Logger } from '@nestjs/common';
import { InjectRedis } from '@nestjs-modules/ioredis';
import Redis from 'ioredis';

type Prefix = 'TSK' | 'PRJ';

@Injectable()
export class NoGeneratorService {
  private readonly logger = new Logger(NoGeneratorService.name);
  private static readonly TTL_SECONDS = 48 * 3600;

  constructor(@InjectRedis() private readonly redis: Redis) {}

  /** 获取今日日期字符串 YYYYMMDD */
  private today(): string {
    const d = new Date();
    const y = d.getFullYear();
    const m = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');
    return `${y}${m}${day}`;
  }

  /** 内部：按前缀+日期递增 */
  private async nextSeq(prefix: Prefix, day: string): Promise<number> {
    const key = `${prefix.toLowerCase()}:seq:${day}`;
    const seq = await this.redis.incr(key);
    // 仅首次设 TTL
    if (seq === 1) {
      await this.redis.expire(key, NoGeneratorService.TTL_SECONDS);
    }
    return seq;
  }

  /** 生成任务编号 TSK-YYYYMMDD-NNN */
  async nextTaskNo(): Promise<string> {
    const day = this.today();
    const seq = await this.nextSeq('TSK', day);
    const padded = seq < 1000 ? String(seq).padStart(3, '0') : String(seq);
    return `TSK-${day}-${padded}`;
  }

  /** 生成项目编号 PRJ-YYYYMMDD-NNN */
  async nextProjectNo(): Promise<string> {
    const day = this.today();
    const seq = await this.nextSeq('PRJ', day);
    const padded = seq < 1000 ? String(seq).padStart(3, '0') : String(seq);
    return `PRJ-${day}-${padded}`;
  }
}

