@use '../../styles./variables' as *;
@use '../../styles/mixins' as *;

.page {
  @include flex-column;
  @include page-base;
}

.top-bar {
  background: $color-primary;
  padding: $space-md;
}

.page-title {
  font-size: $font-lg;
  font-weight: $weight-bold;
  color: $color-text-white;
  display: block;
}

/* ──── 会话列表 ──── */
