import { ForbiddenException, Injectable } from '@nestjs/common';
import { PrismaService } from '../../prisma/prisma.service';
import type { CurrentUserPayload } from '../auth/decorators/current-user.decorator';

/**
 * 审批中心聚合服务
 *
 * 汇总当前企业账号下三类待审批事项：
 *  - 报名申请   pending
 *  - 检查点     submitted
 *  - 交付物     submitted
 *
 * 鉴权：仅 userType === 'company' 可调用；按 companyId 过滤。
 */
@Injectable()
export class ApprovalService {
  constructor(private readonly prisma: PrismaService) {}

  async summary(user: CurrentUserPayload) {
    if (user.userType !== 'company') {
      throw new ForbiddenException('仅企业账号可访问');
    }
    const companyId = BigInt(user.companyId ?? 0);
    if (!companyId) {
      return {
        counts: { applications: 0, checkpoints: 0, deliverables: 0 },
        items: { applications: [], checkpoints: [], deliverables: [] },
        byTask: {},
      };
    }

    // ── 1. 报名申请（pending） ────────────────────────────
    const [apps, appsCount] = await Promise.all([
      this.prisma.taskApplication.findMany({
        where: {
          status: 'pending',
          taskRole: { task: { companyId } },
        },
        orderBy: { createdAt: 'desc' },
        take: 20,
        include: {
          worker: { select: { id: true, realName: true, nickname: true, avatarUrl: true } },
          taskRole: {
            select: {
              id: true,
              roleName: true,
              task: { select: { id: true, title: true, taskNo: true } },
            },
          },
        },
      }),
      this.prisma.taskApplication.count({
        where: { status: 'pending', taskRole: { task: { companyId } } },
      }),
    ]);

    // ── 2. 检查点（submitted） ────────────────────────────
    const [cps, cpsCount] = await Promise.all([
      this.prisma.taskCheckpoint.findMany({
        where: { status: 'submitted', task: { companyId } },
        orderBy: { submittedAt: 'desc' },
        take: 20,
        include: { task: { select: { id: true, title: true, taskNo: true } } },
      }),
      this.prisma.taskCheckpoint.count({
        where: { status: 'submitted', task: { companyId } },
      }),
    ]);

    // ── 3. 交付物（submitted） ────────────────────────────
    // 由 schema 得知 Deliverable.status 枚举含 submitted；只要 companyId 过滤
    const [delivs, delivsCount] = await Promise.all([
      this.prisma.deliverable.findMany({
        where: {
          status: 'submitted',
          task: { companyId },
        },
        orderBy: { updatedAt: 'desc' },
        take: 20,
        include: {
          task: { select: { id: true, title: true, taskNo: true } },
          assignment: {
            select: {
              id: true,
              worker: { select: { id: true, realName: true, nickname: true } },
            },
          },
        },
      }),
      this.prisma.deliverable.count({
        where: { status: 'submitted', task: { companyId } },
      }),
    ]);

    // ── 序列化 ────────────────────────────────────────────
    const appItems = apps.map(a => ({
      applicationId: Number(a.id),
      taskId: Number(a.taskRole.task.id),
      taskNo: a.taskRole.task.taskNo ?? null,
      taskTitle: a.taskRole.task.title,
      roleId: Number(a.taskRole.id),
      roleName: a.taskRole.roleName,
      workerId: Number(a.worker.id),
      workerName: a.worker.realName || a.worker.nickname || `零工#${a.worker.id}`,
      workerAvatar: a.worker.avatarUrl || null,
      intro: a.intro,
      expectPay: a.expectPay ? Number(a.expectPay) : null,
      createdAt: a.createdAt,
    }));

    const cpItems = cps.map(c => ({
      checkpointId: Number(c.id),
      taskId: Number(c.task.id),
      taskNo: c.task.taskNo ?? null,
      taskTitle: c.task.title,
      name: c.name,
      type: c.type,
      plannedDate: c.plannedDate,
      submittedAt: c.submittedAt,
      revisionCount: c.revisionCount,
    }));

    const delivItems = delivs.map(d => ({
      deliverableId: Number(d.id),
      taskId: Number(d.task.id),
      taskNo: d.task.taskNo ?? null,
      taskTitle: d.task.title,
      taskRoleId: Number(d.taskRoleId),
      name: d.name,
      fileName: d.fileName,
      fileUrl: d.fileUrl,
      version: d.currentVersion || d.version,
      workerId: d.assignment?.worker?.id ? Number(d.assignment.worker.id) : null,
      workerName:
        d.assignment?.worker?.realName ||
        d.assignment?.worker?.nickname ||
        null,
      updatedAt: d.updatedAt,
    }));

    // ── 按 taskId 聚合（给任务列表徽标用）─────────────────
    const byTask: Record<string, { applications: number; checkpoints: number; deliverables: number }> = {};
    const bump = (taskId: number, key: 'applications' | 'checkpoints' | 'deliverables') => {
      const k = String(taskId);
      if (!byTask[k]) byTask[k] = { applications: 0, checkpoints: 0, deliverables: 0 };
      byTask[k][key] += 1;
    };
    appItems.forEach(i => bump(i.taskId, 'applications'));
    cpItems.forEach(i => bump(i.taskId, 'checkpoints'));
    delivItems.forEach(i => bump(i.taskId, 'deliverables'));

    return {
      counts: {
        applications: appsCount,
        checkpoints: cpsCount,
        deliverables: delivsCount,
      },
      items: {
        applications: appItems,
        checkpoints: cpItems,
        deliverables: delivItems,
      },
      byTask,
    };
  }
}

import { Controller, Get, UseGuards } from '@nestjs/common';
import { ApiBearerAuth, ApiOperation, ApiTags } from '@nestjs/swagger';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { CurrentUser } from '../auth/decorators/current-user.decorator';
import type { CurrentUserPayload } from '../auth/decorators/current-user.decorator';
import { ApprovalService } from './approval.service';

@ApiTags('审批中心')
@ApiBearerAuth('access-token')
@UseGuards(JwtAuthGuard)
@Controller('approvals')
export class ApprovalController {
  constructor(private readonly svc: ApprovalService) {}

  @Get('summary')
  @ApiOperation({
    summary: '企业待办聚合',
    description: '返回当前企业三类待审批（报名/检查点/交付物）的总数、Top 20 条目 与 按任务ID聚合的徽标数据',
  })
  summary(@CurrentUser() user: CurrentUserPayload) {
    return this.svc.summary(user);
  }
}

