/**
 * WeCreator PC Admin — Global Styles V1.1
 * 基于设计规范 V1.1（画板1496.png 视觉稿）
 */

/* ==================== Design Tokens ==================== */
:root {
  /* 品牌色 */
  --color-primary:          #0858F4;
  --color-primary-hover:    #2470F8;
  --color-primary-active:   #0446D0;
  --color-primary-light:    #4480F8;
  --color-primary-lighter:  #80A8F8;
  --color-primary-bg:       #D0DCFC;
  --color-primary-bg-soft:  #E4ECF8;
  --color-primary-border:   #A0BCF8;

  /* 活力橙 */
  --color-accent:       #FC6400;
  --color-accent-light: #FC9854;
  --color-accent-bg:    #FEE8D5;

  /* 语义色 */
  --color-success:      #38D048;
  --color-success-bg:   #E8FCEC;
  --color-warning:      #FC8C40;
  --color-warning-bg:   #FEF0E0;
  --color-error:        #E8383C;
  --color-error-bg:     #FCE0E0;
  --color-teal:         #34B8A8;
  --color-teal-bg:      #D0F4F0;
  --color-purple:       #E04CFC;
  --color-purple-bg:    #F8E4FC;

  /* 中性色 */
  --color-text-primary:   #181818;
  --color-text-secondary: #505050;
  --color-text-tertiary:  #888888;
  --color-text-disabled:  #C0C0C0;
  --color-border:         #E0E0E0;
  --color-border-light:   #F0F0F0;
  --color-bg-page:        #F0F0F0;
  --color-bg-card:        #FFFFFF;
  --color-bg-hover:       #F8F8F8;
  --color-bg-sidebar:     #FFFFFF;
  --color-bg-header:      #FFFFFF;
  --color-bg-mask:        rgba(0, 0, 0, 0.40);

  /* 任务状态 */
  --status-draft-fg:      #888888;
  --status-draft-bg:      #F0F0F0;
  --status-matching-fg:   #0858F4;
  --status-matching-bg:   #D0DCFC;
  --status-progress-fg:   #34B8A8;
  --status-progress-bg:   #D0F4F0;
  --status-review-fg:     #FC6400;
  --status-review-bg:     #FEE8D5;
  --status-completed-fg:  #38D048;
  --status-completed-bg:  #E8FCEC;
  --status-closed-fg:     #888888;
  --status-closed-bg:     #EEEEEE;

  /* 间距 */
  --space-1: 4px;  --space-2: 8px;   --space-3: 12px;
  --space-4: 16px; --space-5: 20px;  --space-6: 24px;
  --space-8: 32px; --space-10: 40px; --space-12: 48px;

  /* 圆角 */
  --radius-sm: 4px; --radius-md: 6px;
  --radius-lg: 8px; --radius-xl: 12px;

  /* 阴影（轻薄化） */
  --shadow-sm: 0 1px 3px rgba(0, 0, 0, 0.06);
  --shadow-md: 0 2px 8px rgba(0, 0, 0, 0.08);
  --shadow-lg: 0 4px 16px rgba(0, 0, 0, 0.10);

  /* 布局 */
  --layout-header-height: 56px;
  --layout-sider-width: 220px;
  --layout-sider-collapsed: 64px;

  /* 动效 */
  --ease-out: cubic-bezier(0, 0, 0.2, 1);
  --ease-in-out: cubic-bezier(0.4, 0, 0.2, 1);
  --duration-fast: 150ms;
  --duration-normal: 250ms;
}

/* ==================== Reset ==================== */
*, *::before, *::after {
  box-sizing: border-box;
}

html, body {
  margin: 0;
  padding: 0;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'PingFang SC',
    'Hiragino Sans GB', 'Microsoft YaHei', 'Helvetica Neue', sans-serif;
