/**
 * WeCreator — Apple-inspired Theme Tokens
 * 使用 systemBlue / systemGray 等 iOS 17 + macOS Sonoma 规范色
 *
 * 两套主题：
 *   [data-theme="light"]  默认亮色
 *   [data-theme="dark"]   暗色
 *
 * data-theme 属性由 useTheme composable 写在 <html> 上
 */

/* ==================== 默认 / 亮色 ==================== */
:root,
:root[data-theme="light"] {
  /* 品牌色 — iOS systemBlue */
  --color-primary:          #007AFF;
  --color-primary-hover:    #3395FF;
  --color-primary-active:   #0062CC;
  --color-primary-light:    #4DA2FF;
  --color-primary-lighter:  #99C7FF;
  --color-primary-bg:       #D9EBFF;
  --color-primary-bg-soft:  #E8F2FF;
  --color-primary-border:   #B0D4FF;

  /* 活力橙 — systemOrange */
  --color-accent:       #FF9500;
  --color-accent-light: #FFB340;
  --color-accent-bg:    #FFF2E0;

  /* 语义色 — iOS system */
  --color-success:      #34C759;
  --color-success-bg:   #E4F8E9;
  --color-warning:      #FF9500;
  --color-warning-bg:   #FFF2E0;
  --color-error:        #FF3B30;
  --color-error-bg:     #FFE6E4;
  --color-teal:         #30B0C7;
  --color-teal-bg:      #E0F3F7;
  --color-purple:       #AF52DE;
  --color-purple-bg:    #F3E5FA;

  /* 中性色 — systemGrouped / label 系 */
  --color-text-primary:   #000000;
  --color-text-secondary: rgba(60, 60, 67, 0.60);
  --color-text-tertiary:  rgba(60, 60, 67, 0.40);
  --color-text-disabled:  rgba(60, 60, 67, 0.25);
  --color-text-placeholder: rgba(60, 60, 67, 0.30);
  --color-text-inverse:   #FFFFFF;
  --color-border:         #D1D1D6;
  --color-border-light:   #E5E5EA;
  --color-border-strong:  #AEAEB2;

  --color-bg-page:        #F2F2F7;  /* systemGroupedBackground */
  --color-bg-card:        #FFFFFF;  /* secondarySystemGroupedBackground */
  --color-bg-card-2:      #F2F2F7;  /* tertiarySystemGroupedBackground */
  --color-bg-hover:       #F2F2F7;
  --color-bg-sidebar:     rgba(249, 249, 251, 0.80);
  --color-bg-header:      rgba(255, 255, 255, 0.72);
  --color-bg-mask:        rgba(0, 0, 0, 0.35);
  --color-bg-elevated:    #FFFFFF;  /* 悬浮层如 popover/tooltip */

  /* 任务状态 */
  --status-draft-fg:      rgba(60, 60, 67, 0.60);
  --status-draft-bg:      #E5E5EA;
  --status-matching-fg:   #007AFF;
  --status-matching-bg:   #E8F2FF;
  --status-progress-fg:   #30B0C7;
  --status-progress-bg:   #E0F3F7;
  --status-review-fg:     #FF9500;
  --status-review-bg:     #FFF2E0;
  --status-completed-fg:  #34C759;
  --status-completed-bg:  #E4F8E9;
  --status-closed-fg:     rgba(60, 60, 67, 0.40);
  --status-closed-bg:     #EFEFF4;

  /* 阴影 — Apple 双层叠加（细描边 + 柔和落影） */
  --shadow-sm:   0 1px 2px rgba(0, 0, 0, 0.04),   0 0 0 0.5px rgba(0, 0, 0, 0.06);
  --shadow-md:   0 4px 16px rgba(0, 0, 0, 0.06),  0 0 0 0.5px rgba(0, 0, 0, 0.05);
  --shadow-lg:   0 20px 60px rgba(0, 0, 0, 0.15), 0 0 0 0.5px rgba(0, 0, 0, 0.08);
  --shadow-focus-primary: 0 0 0 4px rgba(0, 122, 255, 0.20);

  /* Vibrancy（毛玻璃） */
  --vibrancy-bg: rgba(255, 255, 255, 0.72);
  --vibrancy-filter: saturate(180%) blur(20px);
}

/* ==================== 暗色 ==================== */
:root[data-theme="dark"] {
  /* 品牌色 — iOS Dark Mode systemBlue（更亮） */
  --color-primary:          #0A84FF;
  --color-primary-hover:    #409CFF;
  --color-primary-active:   #0060D0;
  --color-primary-light:    #409CFF;
  --color-primary-lighter:  #76B3FF;
  --color-primary-bg:       rgba(10, 132, 255, 0.24);
  --color-primary-bg-soft:  rgba(10, 132, 255, 0.16);
  --color-primary-border:   rgba(10, 132, 255, 0.40);

  /* 活力橙 — Dark systemOrange */
  --color-accent:       #FF9F0A;
  --color-accent-light: #FFB340;
  --color-accent-bg:    rgba(255, 159, 10, 0.18);

  /* 语义色 — Dark system */
  --color-success:      #30D158;
  --color-success-bg:   rgba(48, 209, 88, 0.18);
  --color-warning:      #FF9F0A;
  --color-warning-bg:   rgba(255, 159, 10, 0.18);
  --color-error:        #FF453A;
  --color-error-bg:     rgba(255, 69, 58, 0.18);
  --color-teal:         #40C8E0;
  --color-teal-bg:      rgba(64, 200, 224, 0.18);
  --color-purple:       #BF5AF2;
  --color-purple-bg:    rgba(191, 90, 242, 0.18);

  /* 中性色 — 深色 labels */
