  --color-bg-elevated:      #2C2C2E;

  /* 任务状态 — 暗色 */
  --status-draft-fg:      rgba(235, 235, 245, 0.60);
  --status-draft-bg:      rgba(235, 235, 245, 0.12);
  --status-matching-fg:   #0A84FF;
  --status-matching-bg:   rgba(10, 132, 255, 0.18);
  --status-progress-fg:   #40C8E0;
  --status-progress-bg:   rgba(64, 200, 224, 0.18);
  --status-review-fg:     #FF9F0A;
  --status-review-bg:     rgba(255, 159, 10, 0.18);
  --status-completed-fg:  #30D158;
  --status-completed-bg:  rgba(48, 209, 88, 0.18);
  --status-closed-fg:     rgba(235, 235, 245, 0.40);
