  /* 阴影 — 深色模式下更深 */
  --shadow-sm:   0 1px 2px rgba(0, 0, 0, 0.40),   0 0 0 0.5px rgba(255, 255, 255, 0.08);
  --shadow-md:   0 4px 16px rgba(0, 0, 0, 0.45),  0 0 0 0.5px rgba(255, 255, 255, 0.06);
  --shadow-lg:   0 20px 60px rgba(0, 0, 0, 0.60), 0 0 0 0.5px rgba(255, 255, 255, 0.08);
  --shadow-focus-primary: 0 0 0 4px rgba(10, 132, 255, 0.30);

  /* Vibrancy（暗色毛玻璃） */
  --vibrancy-bg: rgba(28, 28, 30, 0.72);
  --vibrancy-filter: saturate(180%) blur(20px);
}

/* ==================== 共享令牌（与主题无关） ==================== */
:root {
  /* 间距 — Apple 8pt grid */
  --space-1:  4px;  --space-2: 8px;   --space-3: 12px;
  --space-4: 16px;  --space-5: 20px;  --space-6: 24px;
  --space-8: 32px;  --space-10: 40px; --space-12: 48px;
  --space-16: 64px;

  /* 圆角 — Apple 连续曲率 */
  --radius-sm:   6px;
  --radius-md:  10px;
  --radius-lg:  14px;
  --radius-xl:  20px;
  --radius-2xl: 28px;
  --radius-full: 9999px;

  /* 布局 */
  --layout-header-height:    52px;
  --layout-sider-width:      240px;
  --layout-sider-collapsed:  68px;

  /* 动效 — Apple default curves */
  --ease-out:     cubic-bezier(0.22, 1, 0.36, 1);         /* easeOutExpo 风 */
  --ease-in-out:  cubic-bezier(0.4, 0, 0.6, 1);           /* iOS 默认 */
  --ease-bounce:  cubic-bezier(0.175, 0.885, 0.32, 1.275);
  --duration-fast:    120ms;
  --duration-normal:  240ms;
  --duration-slow:    400ms;

  /* 字体 — SF 栈 */
  --font-family-base:
    -apple-system, BlinkMacSystemFont, "SF Pro Text", "SF Pro Display",
    "Helvetica Neue", "PingFang SC", "Hiragino Sans GB", "Microsoft YaHei", sans-serif;
  --font-family-mono:
    "SF Mono", "Menlo", "Monaco", "Consolas", monospace;
  --font-family-rounded:
    "SF Pro Rounded", -apple-system, BlinkMacSystemFont, sans-serif;
}

/**
 * WeCreator — Apple Design Details
 * 在 theme-apple.css 变量基础上叠加 Apple 视觉细节
 */

/* ========== 全局过渡（主题切换平滑） ========== */
html,
body,
.ant-layout,
.ant-layout-sider,
.ant-layout-header,
.ant-card,
.ant-modal-content,
.ant-dropdown-menu,
.ant-popover-inner,
.ant-menu-item,
.ant-input,
.ant-select-selector,
.ant-btn {
  transition:
    background-color var(--duration-normal) var(--ease-out),
    border-color var(--duration-normal) var(--ease-out),
    color var(--duration-normal) var(--ease-out),
    box-shadow var(--duration-normal) var(--ease-out);
}

/* ========== 字体替换 ========== */
html,
body,
#app,
.ant-layout {
  font-family: var(--font-family-base) !important;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  text-rendering: optimizeLegibility;
  font-feature-settings: "kern" 1, "liga" 1, "calt" 1, "tnum" 1;
}

code,
pre,
.wc-mono {
  font-family: var(--font-family-mono);
}

/* ========== 毛玻璃材质 utility ========== */
.wc-vibrancy {
  background: var(--vibrancy-bg);
  backdrop-filter: var(--vibrancy-filter);
  -webkit-backdrop-filter: var(--vibrancy-filter);
}

.wc-vibrancy-strong {
  background: var(--vibrancy-bg);
  backdrop-filter: saturate(180%) blur(40px);
  -webkit-backdrop-filter: saturate(180%) blur(40px);
}

/* Header / Sidebar 默认应用毛玻璃 */
.ant-layout-header {
  backdrop-filter: var(--vibrancy-filter) !important;
  -webkit-backdrop-filter: var(--vibrancy-filter) !important;
}

.ant-layout-sider {
  backdrop-filter: var(--vibrancy-filter) !important;
  -webkit-backdrop-filter: var(--vibrancy-filter) !important;
}

/* ========== 按钮 Apple 式点击反馈 ========== */
.ant-btn:not(:disabled):active {
  transform: scale(0.97) !important;
  transition-duration: 80ms !important;
}

.ant-btn-primary:not(:disabled):hover {
  box-shadow: 0 4px 14px rgba(0, 122, 255, 0.32) !important;
  transform: translateY(-0.5px);
}

:root[data-theme="dark"] .ant-btn-primary:not(:disabled):hover {
  box-shadow: 0 4px 14px rgba(10, 132, 255, 0.40) !important;
}

/* 大圆角 pill 按钮变体 */
.ant-btn.wc-pill {
  border-radius: var(--radius-full) !important;
  padding-inline: 20px !important;
}

/* ========== 滚动条 Apple 细长款 ========== */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb {
  background: transparent;
