/**
 * useTheme — 统一主题管理
 *
 * 三态：
 *   'light'  强制亮色
 *   'dark'   强制暗色
 *   'auto'   跟随系统（prefers-color-scheme）
 *
 * 持久化 key: wc_theme
 * 实际应用：在 <html data-theme="light|dark"> 上
 */

import { ref, computed, watch, onMounted, onUnmounted } from 'vue'

export type ThemeMode = 'light' | 'dark' | 'auto'

const STORAGE_KEY = 'wc_theme'

// 模块级单例（跨组件共享）
const mode = ref<ThemeMode>(readStoredMode())
const systemDark = ref<boolean>(matchSystemDark())

// 实际生效的 light | dark
const resolved = computed<'light' | 'dark'>(() => {
  if (mode.value === 'auto') return systemDark.value ? 'dark' : 'light'
  return mode.value
})

function readStoredMode(): ThemeMode {
  try {
    const v = localStorage.getItem(STORAGE_KEY)
    if (v === 'light' || v === 'dark' || v === 'auto') return v
  } catch {
    // ignore
  }
  return 'auto'
}

function matchSystemDark(): boolean {
  if (typeof window === 'undefined' || !window.matchMedia) return false
  return window.matchMedia('(prefers-color-scheme: dark)').matches
}

function applyTheme(t: 'light' | 'dark') {
  if (typeof document === 'undefined') return
  document.documentElement.dataset.theme = t
  // 同步 color-scheme 让系统控件（滚动条/表单）跟随
  document.documentElement.style.colorScheme = t
}

// 首次立刻应用
applyTheme(resolved.value)

// 响应式写入
watch(resolved, (t) => applyTheme(t), { immediate: false })

// 监听系统偏好
let mediaQuery: MediaQueryList | null = null
function attachSystemListener() {
  if (typeof window === 'undefined' || !window.matchMedia) return
  mediaQuery = window.matchMedia('(prefers-color-scheme: dark)')
  const handler = (e: MediaQueryListEvent) => {
    systemDark.value = e.matches
  }
  // 兼容旧 API
  if (mediaQuery.addEventListener) {
    mediaQuery.addEventListener('change', handler)
    ;(mediaQuery as any).__wcHandler = handler
  } else if ((mediaQuery as any).addListener) {
    ;(mediaQuery as any).addListener(handler)
    ;(mediaQuery as any).__wcHandler = handler
  }
}

function detachSystemListener() {
  if (!mediaQuery) return
  const handler = (mediaQuery as any).__wcHandler
  if (!handler) return
  if (mediaQuery.removeEventListener) {
    mediaQuery.removeEventListener('change', handler)
  } else if ((mediaQuery as any).removeListener) {
    ;(mediaQuery as any).removeListener(handler)
  }
}

// 全局只挂一次
let attached = false

export function useTheme() {
  onMounted(() => {
    if (!attached) {
      attachSystemListener()
      attached = true
    }
  })

  // 不在 unmount 时拆，因为是全局的

  function setMode(next: ThemeMode) {
    mode.value = next
    try {
      localStorage.setItem(STORAGE_KEY, next)
    } catch {
      // ignore
    }
  }

  function toggle() {
    // 在 light / dark 之间切换（auto 则根据当前计算结果反向）
    const current = resolved.value
    setMode(current === 'dark' ? 'light' : 'dark')
  }

  return {
    mode,       // ThemeMode ref
    resolved,   // 'light' | 'dark' computed
    systemDark, // boolean ref
    setMode,
    toggle,
  }
}

// 供非组件场景直接读（例如 App.vue 的 setup 顶层）
export function getThemeState() {
  return { mode, resolved, systemDark }
}

// 防止 tree-shake，注意在 main.ts 先 import 一次触发初始化
export const __themeInitialized = true

import { createApp } from 'vue'
import { createPinia } from 'pinia'
import router from './router'
import App from './App.vue'

// 主题系统 —— 必须在其他样式前加载（tokens 优先定义）
import './styles/theme-apple.css'
// 全局样式（Reset + Ant 组件覆盖）
import './style.css'
// Apple 风格细节增强（按钮/毛玻璃/滚动条/暗色组件补丁）
import './styles/apple-details.css'
// 响应式
import './assets/responsive.css'

// 触发主题初始化（立即把 data-theme 设到 <html>，避免 FOUC）
import './composables/useTheme'

const app = createApp(App)
app.use(createPinia())
app.use(router)
app.mount('#app')

